{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-mixed-risk-reconnect-plus-spec-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的产物流股问题生成候选提案：一是 liquid-product-5 的下游未连接拓扑错误，二是 vapor-product-5 缺少温度规格。",
      "issues": [
        {
          "title": "liquid-product-5 未连接到下游对象",
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "title": "vapor-product-5 缺少温度规格",
          "citations": [
            "diag-2",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 liquid-product-5 补充下游连接占位",
          "target": {
            "type": "stream",
            "id": "liquid-product-5"
          },
          "rationale": "诊断直接指出该物流未连接到任何下游消费者或导出端；当前证据不足以确定具体目标对象，因此仅建议添加可审查的连接占位，而不假定实际去向。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "liquid-product-5",
              "missing_endpoint": "downstream_consumer_or_export_sink",
              "intent": "connect_stream_to_named_consumer_or_export",
              "notes": "请选择明确的下游单元或导出端后再应用。"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 vapor-product-5 补充温度规格占位",
          "target": {
            "type": "stream",
            "id": "vapor-product-5"
          },
          "rationale": "诊断直接指出该物流缺少温度规格；现有文档仅提供压力，未提供足够证据推断温度数值，因此建议添加温度规格占位供人工确认。",
          "patch": {
            "spec_placeholders": {
              "temperature_c": {
                "status": "required_missing",
                "reason": "STREAM_SPEC_MISSING"
              }
            }
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.9,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-stream-2",
        "flowdoc-stream-3",
        "snapshot-1"
      ]
    }
  ]
}
